花了大约两周的时间,使用electron-vue了解如果调用DLL,现在说一下electron-vue中的配置文件都是干嘛用的 贴一下electron-vue的官方文档 本文参考一只小蚂蚁的文章,感谢大佬无私奉献 build.js打包的入口文件为build.js 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106107108109110111112113114115116117118119120121122123&apos;use strict&apos;// 环境说明process.env.NODE_ENV = &apos;production&apos;// 一个对console.log字体修饰的库，dev的时候，会出现一个花式输出Electron-vueconst &#123; say &#125; = require(&apos;cfonts&apos;)// 终端输出字符串样式，字体样式，字体颜色，背景颜色const chalk = require(&apos;chalk&apos;)// 一个使用globs删除文件和目录的模块， del模块支持多个文件删除[数组]，这是node的原生模块const del = require(&apos;del&apos;)// node原生模块，用来创建子进程const &#123; spawn &#125; = require(&apos;child_process&apos;)// webpackconst webpack = require(&apos;webpack&apos;)// 多个cli滚轮，比如同时安装多个模块，然后在终端会显示滚轮，类似于进度显示const Multispinner = require(&apos;multispinner&apos;)// 需要的配置文件const mainConfig = require(&apos;./webpack.main.config&apos;)const rendererConfig = require(&apos;./webpack.renderer.config&apos;)const webConfig = require(&apos;./webpack.web.config&apos;)const doneLog = chalk.bgGreen.white(&apos; DONE &apos;) + &apos; &apos;const errorLog = chalk.bgRed.white(&apos; ERROR &apos;) + &apos; &apos;const okayLog = chalk.bgBlue.white(&apos; OKAY &apos;) + &apos; &apos;const isCI = process.env.CI || false// 除了clean|web命令，是执行自己的操作，其他指令都是使用build()if (process.env.BUILD_TARGET === &apos;clean&apos;) clean()else if (process.env.BUILD_TARGET === &apos;web&apos;) web()else build()// 同步删除build文件function clean () &#123; del.sync([&apos;build/*&apos;, &apos;!build/icons&apos;, &apos;!build/icons/icon.*&apos;]) console.log(`
$&#123;doneLog&#125;
`) process.exit()&#125;function build () &#123; greeting() del.sync([&apos;dist/electron/*&apos;, &apos;!.gitkeep&apos;]) const tasks = [&apos;main&apos;, &apos;renderer&apos;] const m = new Multispinner(tasks, &#123; preText: &apos;building&apos;, postText: &apos;process&apos; &#125;) let results = &apos;&apos; m.on(&apos;success&apos;, () =&gt; &#123; process.stdout.write(&apos;\x1B[2J\x1B[0f&apos;) console.log(`

$&#123;results&#125;`) console.log(`$&#123;okayLog&#125;take it away $&#123;chalk.yellow(&apos;`electron-builder`&apos;)&#125;
`) process.exit() &#125;) // 打包主进程 pack(mainConfig).then(result =&gt; &#123; results += result + &apos;

&apos; m.success(&apos;main&apos;) &#125;).catch(err =&gt; &#123; m.error(&apos;main&apos;) console.log(`
 $&#123;errorLog&#125;failed to build main process`) console.error(`
$&#123;err&#125;
`) process.exit(1) &#125;) // 打包渲染进程 pack(rendererConfig).then(result =&gt; &#123; results += result + &apos;

&apos; m.success(&apos;renderer&apos;) &#125;).catch(err =&gt; &#123; m.error(&apos;renderer&apos;) console.log(`
 $&#123;errorLog&#125;failed to build renderer process`) console.error(`
$&#123;err&#125;
`) process.exit(1) &#125;)&#125;function pack (config) &#123; return new Promise((resolve, reject) =&gt; &#123; config.mode = &apos;production&apos; webpack(config, (err, stats) =&gt; &#123; if (err) reject(err.stack || err) else if (stats.hasErrors()) &#123; let err = &apos;&apos; stats.toString(&#123; chunks: false, colors: true &#125;) .split(/?
/) .forEach(line =&gt; &#123; err += ` $&#123;line&#125;
` &#125;) reject(err) &#125; else &#123; resolve(stats.toString(&#123; chunks: false, colors: true &#125;)) &#125; &#125;) &#125;)&#125;// 先删除dist目录，除了.gitkeep文件function web () &#123; del.sync([&apos;dist/web/*&apos;, &apos;!.gitkeep&apos;]) webConfig.mode = &apos;production&apos; webpack(webConfig, (err, stats) =&gt; &#123; if (err || stats.hasErrors()) console.log(err) console.log(stats.toString(&#123; chunks: false, colors: true &#125;)) process.exit() &#125;)&#125;// 致意信息 映入眼帘function greeting () &#123; const cols = process.stdout.columns let text = &apos;&apos; if (cols &gt; 85) text = &apos;lets-build&apos; else if (cols &gt; 60) text = &apos;lets-|build&apos; else text = false if (text &amp;&amp; !isCI) &#123; say(text, &#123; colors: [&apos;yellow&apos;], font: &apos;simple3d&apos;, space: false &#125;) &#125; else console.log(chalk.yellow.bold(&apos;
 lets-build&apos;)) console.log()&#125; build.runner.js开发环境使用的配置文件是build.runner.js build.runner.js 主进程 + 渲染进程 打包Electron-vue修改了对开发环境的优化，包括了于开发环境的配置文件隔离，主进程和渲染进程配置文件隔离，编译过程提示等功能 &apos;use strict&apos;const chalk = require(&apos;chalk&apos;)const electron = require(&apos;electron&apos;)const path = require(&apos;path&apos;)const &#123; say &#125; = require(&apos;cfonts&apos;)const &#123; spawn &#125; = require(&apos;child_process&apos;)const webpack = require(&apos;webpack&apos;)const WebpackDevServer = require(&apos;webpack-dev-server&apos;)const webpackHotMiddleware = require(&apos;webpack-hot-middleware&apos;)const mainConfig = require(&apos;./webpack.main.config&apos;)const rendererConfig = require(&apos;./webpack.renderer.config&apos;)let electronProcess = nulllet manualRestart = falselet hotMiddlewarefunction logStats (proc, data) &#123; let log = &apos;&apos; log += chalk.yellow.bold(`┏ $&#123;proc&#125; Process $&#123;new Array((19 - proc.length) + 1).join(&apos;-&apos;)&#125;`) log += &apos;

&apos; if (typeof data === &apos;object&apos;) &#123; data.toString(&#123; colors: true, chunks: false &#125;).split(/?
/).forEach(line =&gt; &#123; log += &apos; &apos; + line + &apos;
&apos; &#125;) &#125; else &#123; log += ` $&#123;data&#125;
` &#125; log += &apos;
&apos; + chalk.yellow.bold(`┗ $&#123;new Array(28 + 1).join(&apos;-&apos;)&#125;`) + &apos;
&apos; console.log(log)&#125;// 启动渲染进程// 整体作用：将dev-client.js和renderer/main.js合并到webpack entry字段，输出到根目录下的/dist/electron/main.js文件中function startRenderer () &#123; // 加载webpack配置 return new Promise((resolve, reject) =&gt; &#123; rendererConfig.entry.renderer = [path.join(__dirname, &apos;dev-client&apos;)].concat(rendererConfig.entry.renderer) rendererConfig.mode = &apos;development&apos; // 创建webpack const compiler = webpack(rendererConfig) // 创建webpack热加载 // webpackHotMiddleware的heartbeat的参数作用并不是检测文件的频率，而是保持服务器链接存活的心跳频率 hotMiddleware = webpackHotMiddleware(compiler, &#123; log: false, heartbeat: 2500 &#125;) // 编译状态监控 # 监听的是 compilation事件 compiler.hooks.compilation.tap(&apos;compilation&apos;, compilation =&gt; &#123; compilation.hooks.htmlWebpackPluginAfterEmit.tapAsync(&apos;html-webpack-plugin-after-emit&apos;, (data, cb) =&gt; &#123; // 钩子函数，检测webpack的编译状态，把其中的html-webpack-plugin-after-emit状态，发布到webpackHotMiddleware中 hotMiddleware.publish(&#123; action: &apos;reload&apos; &#125;) cb() &#125;) &#125;) // 输出打包编译过程 compiler.hooks.done.tap(&apos;done&apos;, stats =&gt; &#123; logStats(&apos;Renderer&apos;, stats) &#125;) // 创建webpack-dev-server const server = new WebpackDevServer( compiler, &#123; contentBase: path.join(__dirname, &apos;../&apos;), quiet: true, before (app, ctx) &#123; // 使用webpackHotMiddleware app.use(hotMiddleware) ctx.middleware.waitUntilValid(() =&gt; &#123; resolve() &#125;) &#125; &#125; ) // 监听窗口 server.listen(9080) &#125;)&#125;// 启动主进程 - 过程与渲染进程是类似的// 创建webpack，实时发布hotMiddleware，主代码热更新function startMain () &#123; // 导入index.dev.js，该文件主要安装electron-debug工具，同时也安装了vue-devtools工具 // webpack.config.main.js与render相比，main不需要去去处理vue，图片， css，html等，只需要对js处理 return new Promise((resolve, reject) =&gt; &#123; mainConfig.entry.main = [path.join(__dirname, &apos;../src/main/index.dev.js&apos;)].concat(mainConfig.entry.main) mainConfig.mode = &apos;development&apos; // 创建主进程的 webpack const compiler = webpack(mainConfig) # 监听的是watch-run事件 compiler.hooks.watchRun.tapAsync(&apos;watch-run&apos;, (compilation, done) =&gt; &#123; logStats(&apos;Main&apos;, chalk.white.bold(&apos;compiling...&apos;)) hotMiddleware.publish(&#123; action: &apos;compiling&apos; &#125;) done() &#125;) // 与render不同，没有使用WebpackDevServer的方式自动更新界面，而是通过webpack的watch模式，不断重新启动程序，类似于electron-forge start compiler.watch(&#123;&#125;, (err, stats) =&gt; &#123; if (err) &#123; console.log(err) return &#125; logStats(&apos;Main&apos;, stats) if (electronProcess &amp;&amp; electronProcess.kill) &#123; manualRestart = true process.kill(electronProcess.pid) electronProcess = null // 重新启动项目 startElectron() setTimeout(() =&gt; &#123; manualRestart = false &#125;, 5000) &#125; resolve() &#125;) &#125;)&#125;// 启动electronfunction startElectron () &#123; var args = [ &apos;--inspect=5858&apos;, path.join(__dirname, &apos;../dist/electron/main.js&apos;) ] // detect yarn or npm and process commandline args accordingly if (process.env.npm_execpath.endsWith(&apos;yarn.js&apos;)) &#123; args = args.concat(process.argv.slice(3)) &#125; else if (process.env.npm_execpath.endsWith(&apos;npm-cli.js&apos;)) &#123; args = args.concat(process.argv.slice(2)) &#125; // 创建主进程执行特别命令 electronProcess = spawn(electron, args) electronProcess.stdout.on(&apos;data&apos;, data =&gt; &#123; electronLog(data, &apos;blue&apos;) &#125;) electronProcess.stderr.on(&apos;data&apos;, data =&gt; &#123; electronLog(data, &apos;red&apos;) &#125;) electronProcess.on(&apos;close&apos;, () =&gt; &#123; if (!manualRestart) process.exit() &#125;)&#125;function electronLog (data, color) &#123; let log = &apos;&apos; data = data.toString().split(/?
/) data.forEach(line =&gt; &#123; log += ` $&#123;line&#125;
` &#125;) if (/[0-9A-z]+/.test(log)) &#123; console.log( chalk[color].bold(&apos;┏ Electron -------------------&apos;) + &apos;

&apos; + log + chalk[color].bold(&apos;┗ ----------------------------&apos;) + &apos;
&apos; ) &#125;&#125;// electron-vue Log输出function greeting () &#123; const cols = process.stdout.columns let text = &apos;&apos; if (cols &gt; 104) text = &apos;electron-vue&apos; else if (cols &gt; 76) text = &apos;electron-|vue&apos; else text = false if (text) &#123; say(text, &#123; colors: [&apos;yellow&apos;], font: &apos;simple3d&apos;, space: false &#125;) &#125; else console.log(chalk.yellow.bold(&apos;
 electron-vue&apos;)) console.log(chalk.blue(&apos; getting ready...&apos;) + &apos;
&apos;)&#125;// 初始函数function init () &#123; greeting() // 主进程和渲染进程都启动完毕 Promise.all([startRenderer(), startMain()]) .then(() =&gt; &#123; startElectron() &#125;) .catch(err =&gt; &#123; console.error(err) &#125;)&#125;init() dev.client.js1234567891011121314151617181920212223242526const hotClient = require(&apos;webpack-hot-middleware/client?noInfo=true&amp;reload=true&apos;)// 注册webpack-hot-middleware监听器hotClient.subscribe(event =&gt; &#123; // 处理Main进程发送的&quot;compiling&quot;的事件 // 实际上在Render进程中还发送了&quot;reload&quot;的消息 if (event.action === &apos;compiling&apos;) &#123; document.body.innerHTML += ` &lt;style&gt; #dev-client &#123; background: #4fc08d; border-radius: 4px; bottom: 20px; box-shadow: 0 4px 5px 0 rgba(0, 0, 0, 0.14), 0 1px 10px 0 rgba(0, 0, 0, 0.12), 0 2px 4px -1px rgba(0, 0, 0, 0.3); color: #fff; font-family: &apos;Source Sans Pro&apos;, sans-serif; left: 20px; padding: 8px 12px; position: absolute; &#125; &lt;/style&gt; &lt;div id=&quot;dev-client&quot;&gt; Compiling Main Process... &lt;/div&gt; ` &#125;&#125;) 页面会显示Compiling Main Process…render webpack打包过程中，hotMiddleware.publish将各种编译状态发送给了hotClient.subscribe。整个webpack-hot-middleware编译过程中发送的编译消息，将会在界面展示一个提示框提示开发者，当然这里也可以自定义订阅事件。 页面渲染页面的渲染都是通过渲染进程完成的，通过webpack.renderer.config.js可以看到渲染进程的入口文件是src/renderer/main.js在普通的electron文件，主进程main.js通过mainWindow.loadURL()标识出渲染进程的html文件，也可以在渲染进程中调用Node的API。在webpack.renderer.config,js中，可以看到使用了一个plugins html-webpack-plugin，这个插件将src/index.ejs模板生成首页的html文件。
